                              className="w-24 border-none bg-transparent p-1 font-mono font-bold uppercase text-sm focus:ring-0"
                              placeholder="#FFFFFF"
                            />
                          </div>

                          <div className="flex items-center gap-2">
                            {colorPresets.map(preset => (
                              <button
