          'Ngày Sinh': item.ngay_sinh,
          'Giới Tính': item.gioi_tinh,
          'CCCD': item.cccd,
          'Trường': item.truong,
          'Môn Thi': item.mon_thi,
          'Điểm Số': item.diem
      }));

      const wb = XLSX.utils.book_new();
      const ws = XLSX.utils.json_to_sheet(exportData);
      XLSX.utils.book_append_sheet(wb, ws, "Ket_Qua_Thi");
